mapper.select:
SELECT ID, QUOTA_NO AS quotaNo, PROJECT_NAME AS projectName, PROJECT_CONTENT AS projectContent, UNIT AS unit, AMOUNT AS amount, CREATE_BY AS createBy, CREATE_TIME AS createTime, UPDATE_BY AS updateBy, UPDATE_TIME AS updateTime FROM E_IC_MAINT_PROJECT_QUOTA WHERE 1 = 1
AND QUOTA_NO LIKE #{quotaNoLike}
AND PROJECT_NAME LIKE #{projectNameLike}
ORDER BY CREATE_TIME DESC
